use crate::library::helper::{RODIO_SUPPORTED_FORMATS, is_rodio_supported};
use crate::library::{ParseTrackIdError, TrackId};
use std::{path::PathBuf, str::FromStr};

// ── TrackId ──────────────────────────────────────────────────────────────────

#[test]
fn track_id_default_is_zero() {
    assert_eq!(TrackId::default().as_u64(), 0);
}

#[test]
fn track_id_increment() {
    let mut id = TrackId::default();
    id.increment();
    assert_eq!(id.as_u64(), 1);
}

#[test]
fn track_id_decrement() {
    let mut id = TrackId::default();
    id.increment();
    id.increment();
    id.decrement();
    assert_eq!(id.as_u64(), 1);
}

#[test]
fn track_id_from_str_valid() {
    let id = TrackId::from_str("42").unwrap();
    assert_eq!(id.as_u64(), 42);
}

#[test]
fn track_id_from_str_zero() {
    let id = TrackId::from_str("0").unwrap();
    assert_eq!(id.as_u64(), 0);
}

#[test]
fn track_id_from_str_invalid_returns_err() {
    assert_eq!(TrackId::from_str("notanumber"), Err(ParseTrackIdError));
}

#[test]
fn track_id_from_str_empty_returns_err() {
    assert_eq!(TrackId::from_str(""), Err(ParseTrackIdError));
}

// ── is_rodio_supported ───────────────────────────────────────────────────────
// These tests use temp files so no test_assets dependency.

use std::fs::File;
use tempfile::tempdir;

#[test]
fn supported_extensions_return_true() {
    let dir = tempdir().unwrap();
    for ext in &RODIO_SUPPORTED_FORMATS {
        let path = dir.path().join(format!("audio.{}", ext));
        File::create(&path).unwrap();
        assert_eq!(
            is_rodio_supported(&path).unwrap(),
            true,
            "Expected true for .{}",
            ext
        );
    }
}

#[test]
fn unsupported_extension_returns_false() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("audio.aiff");
    File::create(&path).unwrap();
    assert_eq!(is_rodio_supported(&path).unwrap(), false);
}

#[test]
fn no_extension_returns_err() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("audiofile");
    File::create(&path).unwrap();
    assert!(is_rodio_supported(&path).is_err());
}

#[test]
fn directory_path_returns_err() {
    let dir = tempdir().unwrap();
    assert!(is_rodio_supported(dir.path()).is_err());
}

#[test]
fn nonexistent_path_returns_err() {
    let path = PathBuf::from("/nonexistent/path/audio.flac");
    assert!(is_rodio_supported(&path).is_err());
}
